def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body (or person) into a single,
    fluent sentence.  The function tries to use a natural phrasing for each
    predicate and joins the resulting clauses with commas and a final “and”.
    """
    if not triples:
        return ""

    # Group triples by subject for better sentence construction
    subject_triples: dict[str, list[Triple]] = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Identify the main subject (usually the celestial body)
    main_subject = None
    discoverer_subjects = set()

    for t in triples:
        if t.predicate.lower() == "discoverer":
            discoverer_subjects.add(t.object)

    # Find main subject (not a discoverer)
    for subj in subject_triples.keys():
        if subj not in discoverer_subjects:
            main_subject = subj
            break

    if main_subject is None:
        main_subject = list(subject_triples.keys())[0] if subject_triples else None

    # Keep object value with units for better readability
    def clean_obj(obj: str) -> str:
        # Keep the full object value including units
        return obj.strip()

    # Simple template mapping for common predicates
    def phrase(t: Triple, is_relative_clause: bool = False, combine_with_prev: bool = False) -> str:
        subj, pred, obj = t.subject, t.predicate, t.object
        clean_obj_val = clean_obj(obj)

        # Normalise predicate strings (remove spaces, lower‑case)
        p = pred.strip().lower()

        # For relative clauses (when subject is discoverer/person), use "who"
        relative_start = "who" if is_relative_clause else None

        # Mapping of predicate to a readable clause
        if p == "discoverer":
            if relative_start:
                return f"who discovered {clean_obj_val}"
            return f"{subj} was discovered by {clean_obj_val}"
        if p == "discovered":
            if relative_start:
                return f"who was discovered on {clean_obj_val}"
            return f"{subj} was discovered on {clean_obj_val}"
        if p == "epoch":
            return f"{subj} has epoch {clean_obj_val}"
        if p == "apoapsis":
            if combine_with_prev:
                return f"with an apoapsis of {clean_obj_val}"
            return f"{subj} has an apoapsis of {clean_obj_val}"
        if p == "periapsis":
            if combine_with_prev:
                return f"with a periapsis of {clean_obj_val}"
            return f"{subj} has a periapsis of {clean_obj_val}"
        if p == "orbitalperiod":
            if combine_with_prev:
                return f"with an orbital period of {clean_obj_val}"
            return f"{subj} has an orbital period of {clean_obj_val}"
        if p == "averagespeed":
            if combine_with_prev:
                return f"with an average speed of {clean_obj_val}"
            return f"{subj} travels at an average speed of {clean_obj_val}"
        if p == "escapevelocity":
            return f"an escape velocity of {clean_obj_val}" if combine_with_prev else f"{subj} has an escape velocity of {clean_obj_val}"
        if p == "mass":
            if combine_with_prev:
                return f"with a mass of {clean_obj_val}"
            return f"{subj} has a mass of {clean_obj_val}"
        if p == "density":
            if combine_with_prev:
                return f"with a density of {clean_obj_val}"
            return f"{subj} has a density of {clean_obj_val}"
        if p == "temperature":
            if combine_with_prev:
                return f"with a temperature of {clean_obj_val}"
            return f"{subj} has a temperature of {clean_obj_val}"
        if p == "maximumtemperature":
            if combine_with_prev:
                return f"with a maximum temperature of {clean_obj_val}"
            return f"{subj} has a maximum temperature of {clean_obj_val}"
        if p == "meantemperature":
            if combine_with_prev:
                return f"with a mean temperature of {clean_obj_val}"
            return f"{subj} has a mean temperature of {clean_obj_val}"
        if p == "minimumtemperature":
            if combine_with_prev:
                return f"with a minimum temperature of {clean_obj_val}"
            return f"{subj} has a minimum temperature of {clean_obj_val}"
        if p == "rotationperiod":
            if combine_with_prev:
                return f"with a rotation period of {clean_obj_val}"
            return f"{subj} has a rotation period of {clean_obj_val}"
        if p == "surfacearea":
            if combine_with_prev:
                return f"with a surface area of {clean_obj_val}"
            return f"{subj} has a surface area of {clean_obj_val}"
        if p == "absolutemagnitude":
            if combine_with_prev:
                return f"with an absolute magnitude of {clean_obj_val}"
            return f"{subj} has an absolute magnitude of {clean_obj_val}"
        if p == "formername":
            return f"was formerly known as {clean_obj_val}" if combine_with_prev else f"{subj} was formerly known as {clean_obj_val}"
        if p == "birthdate":
            return f"was born on {clean_obj_val}" if combine_with_prev else f"was born on {clean_obj_val}"
        if p == "deathdate":
            return f"died on {clean_obj_val}" if combine_with_prev else f"died on {clean_obj_val}"
        if p == "birthplace":
            return f"was born in {clean_obj_val}" if combine_with_prev else f"was born in {clean_obj_val}"
        if p == "deathplace":
            return f"died in {clean_obj_val}" if combine_with_prev else f"died in {clean_obj_val}"
        if p == "deathcause":
            return f"died of {clean_obj_val}" if combine_with_prev else f"died of {clean_obj_val}"
        if p == "nationality" or p == "stateoforigin":
            return f"is from {clean_obj_val}" if combine_with_prev else f"is from {clean_obj_val}"
        if p == "almamater":
            return f"studied at {clean_obj_val}" if combine_with_prev else f"studied at {clean_obj_val}"
        if p == "doctoralstudent":
            return f"supervised {clean_obj_val}" if combine_with_prev else f"supervised {clean_obj_val}"
        # Fallback generic wording
        return f"{subj} {pred} {clean_obj_val}"

    # Build sentence parts, trying to create one complex sentence
    main_clauses = []
    relative_clauses = []
    processed_subjects = set()

    # First, collect main subject information (celestial body)
    if main_subject and main_subject in subject_triples:
        main_triples = subject_triples[main_subject]
        for i, t in enumerate(main_triples):
            clause = phrase(t, is_relative_clause=False, combine_with_prev=(i > 0))
            main_clauses.append(clause)
        processed_subjects.add(main_subject)

    # Then collect information about related subjects (like discoverers)
    for subj, tlist in subject_triples.items():
        if subj in processed_subjects:
            continue

        is_relative = subj in discoverer_subjects
        subj_clauses = []
        for i, t in enumerate(tlist):
            clause = phrase(t, is_relative_clause=False, combine_with_prev=(i > 0))
            subj_clauses.append(clause)

        if is_relative and subj_clauses:
            # Join this person's attributes with "who" for relative clause
            relative_start = "who " + subj_clauses[0].lower()
            if len(subj_clauses) > 1:
                relative_rest = ", ".join(subj_clauses[1:-1])
                if subj_clauses[-1]:
                    relative_rest += ", and " + subj_clauses[-1]
                relative_clauses.append(relative_start + relative_rest)
            else:
                relative_clauses.append(relative_start)
        else:
            main_clauses.extend(subj_clauses)

        processed_subjects.add(subj)

    # Join main clauses with relative clauses into one complex sentence
    if main_clauses:
        main_sentence = main_clauses[0]
        if len(main_clauses) > 1:
            main_sentence = ", ".join(main_clauses[:-1]) + ", and " + main_clauses[-1]

        # Insert relative clause after the discoverer mention
        if relative_clauses:
            # Find where to insert relative clause (after discoverer phrase)
            insert_pos = -1
            for i, clause in enumerate(main_clauses):
                if "discovered by" in clause.lower() or "discovered on" in clause.lower():
                    insert_pos = i
                    break

            if insert_pos >= 0:
                # Insert relative clause after the discoverer clause
                relative_sentence = ", " + relative_clauses[0]
                main_clauses.insert(insert_pos + 1, relative_sentence)
                # Rebuild the sentence
                if len(main_clauses) > 2:
                    sentence = ", ".join(main_clauses[:-1]) + ", and " + main_clauses[-1] + "."
                else:
                    sentence = ", ".join(main_clauses) + "."
            else:
                # Append relative clause at the end
                sentence = main_sentence + ", " + relative_clauses[0] + "."
        else:
            sentence = main_sentence + "."
    elif relative_clauses:
        sentence = relative_clauses[0] + "."
    else:
        sentence = ""

    # Capitalise first character
    if sentence:
        return sentence[0].upper() + sentence[1:]
    return sentence

